$(() => {
    // 防止脚本被多次加载时重复初始化
    if (window.parent.__promptSystemLoaded) {
        console.log('[提示系统] 已加载，跳过重复初始化');
        return;
    }
    window.parent.__promptSystemLoaded = true;

    console.log('[提示系统] 已加载');

    var parentDoc = window.parent.document;
    var currentPrompt = null;
    var isDragging = false;

    // 创建提示容器
    function createPromptContainer() {
        var $container = $('<div>')
            .attr('id', 'location-prompt-container')
            .css({
                position: 'fixed',
                top: '80px',
                right: '16px',
                zIndex: 9999,
                width: 'calc(100vw - 32px)',
                maxWidth: '240px', // 进一步缩小体积
                display: 'flex',
                flexDirection: 'column',
                pointerEvents: 'none',
                userSelect: 'none' // 防止拖拽时选中文本
            })
            .appendTo(parentDoc.body);

        return $container;
    }

    // 创建提示卡片
    function createPromptCard(title, actions) {
        var $cardContainer = $('<div>').css({
            position: 'relative',
            width: '100%',
            pointerEvents: 'none',
            marginBottom: '16px'
        });

        var $card = $('<div>')
            .css({
                width: '100%',
                background: 'rgba(255, 255, 255, 0.92)', // 白色系主题
                backdropFilter: 'blur(20px) saturate(180%)',
                WebkitBackdropFilter: 'blur(20px) saturate(180%)',
                border: '1px solid rgba(0, 0, 0, 0.06)',
                borderRadius: '16px',
                padding: '12px', // 缩小内边距
                color: '#1e293b',
                boxShadow: '0 12px 32px rgba(0, 0, 0, 0.08), 0 2px 6px rgba(0,0,0,0.04)',
                transform: 'translateX(120%) scale(0.95)',
                opacity: 0,
                transition: 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1), opacity 0.5s', // 拖拽时不使用过渡
                fontFamily: 'system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
                pointerEvents: 'auto',
                boxSizing: 'border-box'
            });

        // 拖拽逻辑 (鼠标 + 触摸双支持)
        var dragStartX, dragStartY, initialTop, initialLeft;

        function getPointerXY(e) {
            if (e.touches && e.touches[0])        return { x: e.touches[0].clientX,        y: e.touches[0].clientY };
            if (e.changedTouches && e.changedTouches[0]) return { x: e.changedTouches[0].clientX, y: e.changedTouches[0].clientY };
            return { x: e.clientX, y: e.clientY };
        }

        function handleDragStart(e) {
            if ($(e.target).closest('button, .no-drag').length > 0) return;
            var isTouch = e.type === 'touchstart';
            if (isTouch) e.preventDefault(); // 阻止页面滚动（非 passive 监听器上才有效）

            isDragging = true;
            var pos = getPointerXY(e);
            dragStartX = pos.x;
            dragStartY = pos.y;

            var $container = $('#location-prompt-container', parentDoc);
            if (!$container.offset()) return;

            // 统一切换为 left 定位，方便计算
            if ($container.css('right') !== 'auto') {
                var ww = window.parent.innerWidth;
                initialLeft = ww - $container.outerWidth() - (parseFloat($container.css('right')) || 0);
                $container.css({ right: 'auto', left: initialLeft + 'px' });
            } else {
                initialLeft = parseFloat($container.css('left')) || 0;
            }
            initialTop = parseFloat($container.css('top')) || 0;

            $container.css({ transition: 'none', cursor: 'grabbing' });
            $card.css('cursor', 'grabbing');

            if (isTouch) {
                // 必须用原生非 passive 监听器，jQuery touch 默认 passive 无法 preventDefault
                parentDoc.addEventListener('touchmove', nativeTouchMove, { passive: false });
                parentDoc.addEventListener('touchend',  nativeTouchEnd,  { passive: true  });
            } else {
                $(parentDoc).on('mousemove.promptDrag', handleDragMove);
                $(parentDoc).on('mouseup.promptDrag',   handleDragEnd);
            }
        }

        function handleDragMove(e) {
            if (!isDragging) return;
            var pos = getPointerXY(e);
            var newLeft = initialLeft + pos.x - dragStartX;
            var newTop  = initialTop  + pos.y - dragStartY;

            var $container = $('#location-prompt-container', parentDoc);
            var ww = window.parent.innerWidth;
            var wh = window.parent.innerHeight;
            newLeft = Math.max(0, Math.min(newLeft, ww - $container.outerWidth()));
            newTop  = Math.max(0, Math.min(newTop,  wh - $container.outerHeight()));
            $container.css({ left: newLeft + 'px', top: newTop + 'px' });
        }

        function handleDragEnd(e) {
            if (!isDragging) return;
            isDragging = false;
            var $container = $('#location-prompt-container', parentDoc);
            $container.css({ cursor: 'default' });
            $card.css('cursor', 'grab');
            $(parentDoc).off('mousemove.promptDrag mouseup.promptDrag');
        }

        // 原生触摸代理，在非 passive 监听器里阻止页面滚动
        function nativeTouchMove(e) {
            e.preventDefault();
            handleDragMove(e);
        }
        function nativeTouchEnd(e) {
            handleDragEnd(e);
            parentDoc.removeEventListener('touchmove', nativeTouchMove);
            parentDoc.removeEventListener('touchend',  nativeTouchEnd);
        }

        // 鼠标用 jQuery，触摸用原生非 passive 监听器
        $card.on('mousedown', handleDragStart);
        $card[0].addEventListener('touchstart', handleDragStart, { passive: false });
        $card.css('cursor', 'grab');

        // 侧边贴边收缩按钮 (当卡片收起时显示)
        var $handle = $('<div>')
            .addClass('no-drag') // 防止点击时触发拖拽
            .css({
                position: 'absolute',
                right: '-16px', // 紧贴屏幕右侧
                top: '10px', // 适应变小的卡片
                background: 'rgba(255, 255, 255, 0.95)',
                backdropFilter: 'blur(10px)',
                border: '1px solid rgba(0, 0, 0, 0.08)',
                borderRight: 'none',
                borderRadius: '12px 0 0 12px',
                padding: '10px 6px', // 缩小按钮
                cursor: 'pointer',
                boxShadow: '-4px 4px 12px rgba(0,0,0,0.05)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#64748b',
                fontSize: '10px',
                fontWeight: 'bold',
                transform: 'translateX(100%)',
                opacity: 0,
                transition: 'all 0.4s cubic-bezier(0.16, 1, 0.3, 1)',
                pointerEvents: 'none',
                zIndex: -1
            })
            .html('◀')
            .hover(
                function() { $(this).css({ color: '#3b82f6', background: '#ffffff', paddingRight: '10px', right: '-16px' }); },
                function() { $(this).css({ color: '#64748b', background: 'rgba(255, 255, 255, 0.95)', paddingRight: '6px', right: '-16px' }); }
            )
            .on('click', function(e) {
                e.stopPropagation(); // 阻止事件冒泡到拖拽
                toggleCollapse(false); // 展开
            });

        function toggleCollapse(collapsed) {
            var $container = $('#location-prompt-container', parentDoc);

            if (collapsed) {
                // 如果是被拖拽过的，先重置回右侧，方便收缩动画
                if ($container.css('right') === 'auto') {
                    $container.css({
                        left: 'auto',
                        right: '16px'
                    });
                }

                // 收起状态
                $card.css({
                    transform: 'translateX(calc(100% + 32px)) scale(0.95)',
                    opacity: 0,
                    pointerEvents: 'none'
                });
                $handle.css({
                    transform: 'translateX(0)',
                    opacity: 1,
                    pointerEvents: 'auto'
                });
            } else {
                // 展开状态
                $card.css({
                    transform: 'translateX(0) scale(1)',
                    opacity: 1,
                    pointerEvents: 'auto'
                });
                $handle.css({
                    transform: 'translateX(100%)',
                    opacity: 0,
                    pointerEvents: 'none'
                });
            }
        }

        var $header = $('<div>')
            .addClass('drag-handle') // 拖拽把手标识
            .css({
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginBottom: '10px',
                paddingBottom: '8px',
                borderBottom: '1px solid rgba(0, 0, 0, 0.05)'
            });

        var $titleWrapper = $('<div>')
            .css({
                display: 'flex',
                alignItems: 'center',
                gap: '6px'
            });

        var $icon = $('<div>')
            .css({
                width: '6px',
                height: '6px',
                borderRadius: '50%',
                background: '#3b82f6',
                boxShadow: '0 0 6px rgba(59, 130, 246, 0.5)'
            });

        var $title = $('<div>')
            .css({
                fontSize: '14px', // 缩小字号
                fontWeight: '600',
                letterSpacing: '0.2px',
                color: '#0f172a'
            })
            .text(title);

        $titleWrapper.append($icon, $title);

        var $headerActions = $('<div>')
            .css({
                display: 'flex',
                gap: '4px'
            });

        // 拖拽提示图标 (仅视觉效果)
        var $dragIcon = $('<div>')
             .css({
                 width: '24px',
                 height: '24px',
                 display: 'flex',
                 alignItems: 'center',
                 justifyContent: 'center',
                 color: '#94a3b8',
                 fontSize: '12px',
                 marginRight: '2px'
             })
             .html('⋮⋮'); // 拖拽把手图标

        // 收缩按钮
        var $collapseBtn = $('<div>')
            .addClass('no-drag')
            .css({
                width: '24px',
                height: '24px',
                borderRadius: '6px',
                background: 'transparent',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: 'pointer',
                fontSize: '10px',
                color: '#64748b',
                transition: 'all 0.2s ease'
            })
            .html('▶')
            .hover(
                function() { $(this).css({ background: 'rgba(0,0,0,0.04)', color: '#3b82f6' }); },
                function() { $(this).css({ background: 'transparent', color: '#64748b' }); }
            )
            .on('click', function(e) {
                e.stopPropagation();
                toggleCollapse(true);
            });

        // 关闭按钮
        var $closeBtn = $('<div>')
            .addClass('no-drag')
            .css({
                width: '24px',
                height: '24px',
                borderRadius: '6px',
                background: 'transparent',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: 'pointer',
                fontSize: '16px',
                lineHeight: '1',
                color: '#64748b',
                transition: 'all 0.2s ease'
            })
            .html('&times;')
            .hover(
                function() { $(this).css({ background: 'rgba(239, 68, 68, 0.1)', color: '#ef4444' }); },
                function() { $(this).css({ background: 'transparent', color: '#64748b' }); }
            )
            .on('click', function(e) {
                e.stopPropagation();
                hidePrompt();
            });

        $headerActions.append($dragIcon, $collapseBtn, $closeBtn);
        $header.append($titleWrapper, $headerActions);
        $card.append($header);

        if (actions && actions.length > 0) {
            var $actions = $('<div>').css({ display: 'flex', flexDirection: 'column', gap: '6px' }); // 减小按钮间距

            actions.forEach(function(action) {
                var $btn = $('<button>')
                    .css({
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        background: '#f8fafc',
                        border: '1px solid #e2e8f0',
                        borderRadius: '8px', // 缩小圆角
                        padding: '8px 12px', // 缩小按钮内边距
                        color: '#334155',
                        fontSize: '12px', // 缩小按钮字号
                        fontWeight: '500',
                        cursor: 'pointer',
                        transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
                        textAlign: 'left',
                        boxShadow: '0 1px 2px rgba(0, 0, 0, 0.02)',
                        width: '100%',
                        boxSizing: 'border-box'
                    })
                    .html(`<span>${action.label}</span><span class="action-icon" style="font-size: 11px; opacity: 0; transform: translateX(-4px); transition: all 0.3s ease; color: #3b82f6;">➔</span>`)
                    // PC hover 效果
                    .on('mouseenter', function() {
                        $(this).css({ background: '#ffffff', borderColor: '#cbd5e1', color: '#0f172a', transform: 'translateY(-1px)', boxShadow: '0 4px 10px rgba(0,0,0,0.04)' });
                        $(this).find('.action-icon').css({ opacity: 1, transform: 'translateX(0)' });
                    })
                    .on('mouseleave', function() {
                        $(this).css({ background: '#f8fafc', borderColor: '#e2e8f0', color: '#334155', transform: 'translateY(0)', boxShadow: '0 1px 2px rgba(0,0,0,0.02)' });
                        $(this).find('.action-icon').css({ opacity: 0, transform: 'translateX(-4px)' });
                    })
                    // 手机触摸按下/松开反馈
                    .on('touchstart', function(e) {
                        e.stopPropagation();
                        $(this).css({ background: '#f0f4ff', borderColor: '#93c5fd', color: '#1d4ed8', transform: 'scale(0.97)' });
                        $(this).find('.action-icon').css({ opacity: 1, transform: 'translateX(0)' });
                    })
                    .on('touchend touchcancel', function() {
                        $(this).css({ background: '#f8fafc', borderColor: '#e2e8f0', color: '#334155', transform: 'scale(1)' });
                        $(this).find('.action-icon').css({ opacity: 0, transform: 'translateX(-4px)' });
                    })
                    .on('click', function(e) {
                        e.stopPropagation();
                        $(this).css({ transform: 'scale(0.97)' });
                        setTimeout(() => {
                            console.log('[提示系统] 执行命令:', action.command);
                            executeCommand(action.command);
                        }, 150);
                    });

                $actions.append($btn);
            });

            $card.append($actions);
        }

        $cardContainer.append($card, $handle);
        $cardContainer.data('toggleCollapse', toggleCollapse);
        $cardContainer.data('card', $card);
        $cardContainer.data('handle', $handle);

        return $cardContainer;
    }

    // 显示提示
    function showPrompt(title, actions) {
        hidePrompt();

        var $container = $('#location-prompt-container', parentDoc);
        if ($container.length === 0) {
            $container = createPromptContainer();
        }

        // 立即清除所有残留的旧卡片（防止动画未结束时出现两张）
        $container.empty();

        currentPrompt = createPromptCard(title, actions);
        $container.append(currentPrompt);

        setTimeout(function() {
            if (currentPrompt && currentPrompt.data('toggleCollapse')) {
                currentPrompt.data('toggleCollapse')(false);
            }
        }, 50);
    }

    // 隐藏提示
    function hidePrompt() {
        if (currentPrompt) {
            var promptToRemove = currentPrompt;
            var $cardToHide = promptToRemove.data('card');
            var $handleToHide = promptToRemove.data('handle');

            if ($cardToHide) $cardToHide.css({ transform: 'translateX(120%) scale(0.95)', opacity: 0 });
            if ($handleToHide) $handleToHide.css({ transform: 'translateX(100%)', opacity: 0 });

            currentPrompt = null;
            setTimeout(function() {
                if (promptToRemove) {
                    promptToRemove.remove();
                }
            }, 500);
        }
    }

    // 执行命令
    function executeCommand(command) {
        try {
            hidePrompt();

            if (typeof window.parent.Generate === 'function') {
                window.parent.Generate(command);
            } else if (typeof sendRaw === 'function') {
                sendRaw(command);
            } else {
                var $textarea = $('#send_textarea', parentDoc);
                if ($textarea.length > 0) {
                    $textarea.val(command);
                    var $sendBtn = $('#send_but', parentDoc);
                    if ($sendBtn.length > 0) {
                        $sendBtn.click();
                    }
                }
            }
        } catch (e) {
            console.error('[提示系统] 发送失败:', e);
        }
    }

    // 初始化
    async function init() {
        try {
            if (typeof waitGlobalInitialized === 'function') {
                await waitGlobalInitialized('Mvu');
            }

            if (typeof eventOn === 'function' && typeof Mvu !== 'undefined' && Mvu.events) {
                eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, function(variables) {
                    var location = _.get(variables, 'stat_data.主角.所在区域');

                    if (location && location.includes('齿轮与花')) {
                        showPrompt('当前处于齿轮与花工作室', [
                            { label: '购买物品', command: '「在齿轮与花工作室中购买商品」' },
                            { label: '炼造装备', command: '「在齿轮与花工作室中炼造装备」' },
                            { label: '出售战利品', command: '「在齿轮与花工作室中出售战利品」' }
                        ]);
                    } else if (location && location.includes('渡鸦')) {
                        showPrompt('当前处于渡鸦酒馆', [
                            { label: '购买商品', command: '「在渡鸦酒馆中购买商品」' },
                            { label: '接取委托', command: '「在渡鸦酒馆中接取委托」' },
                            { label: '出售战利品', command: '「在渡鸦酒馆中出售战利品」' }
                        ]);
                    } else if (location && location.includes('皇家武器工坊')) {
                        showPrompt('当前处于皇家武器工坊', [
                            { label: '购买武器', command: '「在皇家武器工坊中购买武器」' },
                            { label: '炼造装备', command: '「在皇家武器工坊中炼造装备」' },
                            { label: '出售战利品', command: '「在皇家武器工坊中出售战利品」' }
                        ]);
                    } else if (location && location.includes('蒸汽动力')) {
                        showPrompt('当前处于蒸汽动力', [
                            { label: '购买武器', command: '「在蒸汽动力中购买武器」' },
                            { label: '炼造装备', command: '「在蒸汽动力中炼造装备」' },
                            { label: '出售战利品', command: '「在蒸汽动力中出售战利品」' }
                        ]);
                    } else {
                        hidePrompt();
                    }
                });
            }

        } catch (e) {
            console.error('[提示系统] 初始化失败:', e);
        }
    }

    init();

    // 清理
    $(window).on('pagehide', function() {
        hidePrompt();
        $('#location-prompt-container', parentDoc).remove();
        window.parent.__promptSystemLoaded = false;
    });

    if (typeof eventOn === 'function') {
        eventOn('CHAT_CHANGED', function() {
            hidePrompt();
        });
    }
});
